// main.jsx / index.jsx
import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

createRoot(document.getElementById('root')).render(
  <StrictMode>
    <App />
  </StrictMode>
);

function App() {
  return (
    <>
      <LegacySection />  {/* not checked */}
      <StrictMode>
        <NewFeature />   {/* StrictMode checks enabled here */}
      </StrictMode>
    </>
  );
}

// BUG: module-level mutation during render
let renderCount = 0;

function VisitBanner() {
  renderCount++; // impure — increments every render call
  return <div>This page has been rendered {renderCount} times.</div>;
}

// Normal mode: mount shows "1", then "2" on first re-render
// StrictMode: mount shows "2" (first call discarded, second committed)
// The double from StrictMode reveals the impurity immediately

// FIX: pure component — render reads, does not write
function VisitBanner({ visitCount }) {
  return <div>This page has been visited {visitCount} times.</div>;
  // visitCount is passed as a prop — pure read, no mutation
}

// BUG: effect that does not clean up a subscription
function LiveFeed({ url }) {
  useEffect(() => {
    const socket = new WebSocket(url);
    socket.onmessage = e => setMessages(m => [...m, e.data]);
    // Missing cleanup! In StrictMode, two WebSocket connections open
    // and neither is closed — resource leak exposed
  }, [url]);
}

// FIX: always return a cleanup function
function LiveFeed({ url }) {
  useEffect(() => {
    const socket = new WebSocket(url);
    socket.onmessage = e => setMessages(m => [...m, e.data]);

    return () => {
      socket.close(); // cleanup runs between the two setup calls in StrictMode
    };
  }, [url]);
}

// Timer effect — setup starts, cleanup cancels, setup starts again
function Countdown({ seconds }) {
  const [remaining, setRemaining] = useState(seconds);

  useEffect(() => {
    if (remaining <= 0) return;
    const id = setInterval(() => {
      setRemaining(r => r - 1);
    }, 1000);
    return () => clearInterval(id); // cleanup cancels the interval
    // StrictMode: start interval → cancel → start again → fine
  }, [remaining]);

  return <div>{remaining}s</div>;
}

// Analytics effect — in StrictMode, track fires twice on mount
function PageView({ pageId }) {
  useEffect(() => {
    analytics.track('page_view', { pageId });
    // No cleanup possible for analytics — this fires twice in dev
    // Solution: accept this as a dev-only artefact, or use a ref to guard
  }, [pageId]);
}

// Guard pattern for truly one-shot effects
function PageView({ pageId }) {
  const tracked = useRef(false);
  useEffect(() => {
    if (!tracked.current) {
      tracked.current = true;
      analytics.track('page_view', { pageId });
    }
    return () => { tracked.current = false; }; // reset on cleanup
  }, [pageId]);
}

function ExpensiveComponent() {
  // This initializer function is called twice in StrictMode (dev only)
  const [data, setData] = useState(() => {
    console.log('initializing state'); // prints twice in StrictMode
    return computeExpensiveDefault();
  });
  // ...
}

// Impure initializer (bug):
let initCount = 0;
function Buggy() {
  const [value] = useState(() => {
    initCount++; // mutates external state — wrong value in StrictMode
    return initCount;
  });
  return <div>{value}</div>; // shows "2" not "1" in StrictMode
}

// BUG: reducer mutates state directly
function badReducer(state, action) {
  if (action.type === 'add') {
    state.items.push(action.item); // MUTATION — impure reducer
    return state;
  }
  return state;
}
// In StrictMode: dispatch runs reducer twice, pushing the item twice!

// FIX: reducer returns new state
function goodReducer(state, action) {
  if (action.type === 'add') {
    return { ...state, items: [...state.items, action.item] };
  }
  return state;
}
// In StrictMode: dispatch runs reducer twice, each returns a new array
// with one item — idempotent, correct

function DebugComponent() {
  console.log('rendering'); // prints twice per render in StrictMode
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// StrictMode warns about deprecated usage:
class LegacyComponent extends React.Component {
  // Using legacy string ref — StrictMode logs a warning
  render() {
    return <div ref="myRef">...</div>;
  }
}

// useMemo factory is called twice in StrictMode (dev)
function ExpensiveTable({ data }) {
  const processed = useMemo(() => {
    console.log('computing'); // prints twice in dev with StrictMode
    return data.map(row => ({ ...row, total: row.a + row.b }));
  }, [data]);

  return <Table rows={processed} />;
}

// Pure factory: same result both calls — no problem
// Impure factory (side effect): bug is revealed by inconsistency

// Context consumer double-render in StrictMode
function ThemeConsumer() {
  const theme = useContext(ThemeContext);
  console.log('consumer render', theme); // twice per render in dev
  return <div className={theme}>Content</div>;
}

// Example: wrapping a legacy library that has issues with effect double-invoke
function LegacyChartWrapper({ data }) {
  const containerRef = useRef(null);
  const chartRef = useRef(null);

  useEffect(() => {
    // Create chart on mount
    chartRef.current = createLegacyChart(containerRef.current, data);

    return () => {
      // Ensure cleanup so StrictMode double-invoke works correctly
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [data]);

  return <div ref={containerRef} />;
}

// Progressive adoption: wrap one feature at a time
function App() {
  return (
    <div>
      <Header />               {/* legacy — not yet in StrictMode */}
      <StrictMode>
        <NewDashboard />       {/* cleaned up — in StrictMode */}
      </StrictMode>
      <LegacyFooter />        {/* legacy — not yet in StrictMode */}
    </div>
  );
}

import { StrictMode } from 'react';
import { render, screen } from '@testing-library/react';

function renderStrict(ui) {
  return render(<StrictMode>{ui}</StrictMode>);
}

test('counter increments once per click', async () => {
  renderStrict(<Counter />);
  // Even under StrictMode double-invoke, initial state should show 0
  expect(screen.getByText('0')).toBeInTheDocument();
});

// Or configure as a global wrapper in your test setup:
// jest.setup.js / vitest.setup.js
import { configure } from '@testing-library/react';
configure({
  wrapper: ({ children }) => <StrictMode>{children}</StrictMode>
});
